func (v vslAgentLevelDo) Delete(models ...*fxshop.VslAgentLevel) (result gen.ResultInfo, err error) {
	return v.DO.Delete(models)
}

func (v *vslAgentLevelDo) withDO(do gen.Dao) *vslAgentLevelDo {
	v.DO = *do.(*gen.DO)
	return v
}
